// Time:  O(n)
// Space: O(1)

// string
class Solution {
public:
    bool isBalanced(string num) {
        const auto& f = [&](int i) {
            int result = 0;
            for (; i < size(num); i += 2) {
                result += num[i] - '0';
            }
            return result;
        };

        return f(0) == f(1);
    }
};

# Time:  O(n)
# Space: O(1)

# string
class Solution(object):
    def isBalanced(self, num):
        """
        :type num: str
        :rtype: bool
        """
        return sum(ord(num[i])-ord('0') for i in xrange(0, len(num), 2)) == sum(ord(num[i])-ord('0') for i in xrange(1, len(num), 2))
